/* ════════════════════════════════════════════════════════
   PAGE NAVIGATION — FLIPBOOK
════════════════════════════════════════════════════════ */

const PAGE_IDS  = ['page-sim','page-signs','page-general','page-quiz'];
const PAGE_NAMES= ['DRIVING SIMULATOR','ROAD SIGNS','GENERAL Q&A','THEORY QUIZ'];
const NAV_IDS   = ['nav-sim','nav-signs','nav-general','nav-quiz'];
let currentPage = 0;

function showPage(id, idx){
  const direction = idx > currentPage ? 'right' : 'left';

  PAGE_IDS.forEach((pid, i) => {
    const el = document.getElementById(pid);
    el.className = 'page ';
    if(i === idx){
      el.className += 'state-active';
    } else if(i < idx){
      el.className += 'state-hidden-left';
    } else {
      el.className += 'state-hidden-right';
    }
  });

  NAV_IDS.forEach((nid,i)=>{
    document.getElementById(nid).classList.toggle('active', i===idx);
  });

  document.querySelectorAll('.page-dot').forEach((d,i)=>{
    d.classList.toggle('active', i===idx);
  });

  document.getElementById('headerPageName').textContent = PAGE_NAMES[idx];
  currentPage = idx;

  // Stop both TTS instances and show only the relevant bar
  FAQ_TTS.stop();
  QUIZ_TTS.stop();
  document.getElementById('tts-bar-faq') .classList.toggle('tts-visible', idx === 2);
  document.getElementById('tts-bar-quiz').classList.toggle('tts-visible', idx === 3);

  // Lazy init
  if(id==='quiz' && !quizInitDone){ quizInitDone=true; renderQuizStart(); }
}

/* ════════════════════════════════════════════════════════
   SIMULATOR ENGINE
════════════════════════════════════════════════════════ */

const canvas = document.getElementById('gameCanvas');
const ctx    = canvas.getContext('2d');

let keys={}, vehicles=[], selectedCar=null, dragging=false, trafficEnabled=true;

/* ── Map ── */
const map = new Image();
map.src = ASSET_Map_png;

/* ── Vehicle definitions ── */
const VEHICLE_DEFS = [
  {file:ASSET_car1_png,   label:'Blue Sedan',   w:24, h:48, color:'#29b6f6'},
  {file:ASSET_car10_png,  label:'Red Sedan',    w:24, h:48, color:'#ef5350'},
  {file:ASSET_car5_png,   label:'White Sedan',  w:24, h:44, color:'#eeeeee'},
  {file:ASSET_car6_png,   label:'White Saloon', w:24, h:46, color:'#e0e0e0'},
  {file:ASSET_car4_png,   label:'Taxi',         w:18, h:36, color:'#f5c518'},
  {file:ASSET_car2_png,   label:'Van',          w:26, h:52, color:'#bdbdbd'},
  {file:ASSET_car3_png,   label:'Pick-Up',      w:26, h:54, color:'#555'},
  {file:ASSET_car10o_png, label:'SUV',          w:28, h:56, color:'#607d8b'},
  {file:ASSET_car7_png,   label:'Police',       w:24, h:48, color:'#1565c0', special:'police'},
  {file:ASSET_car8_png,   label:'Police 2',     w:24, h:50, color:'#263238', special:'police'},
  {file:ASSET_car9_png,   label:'Ambulance',    w:24, h:48, color:'white',   special:'ambulance'},
];

let carImages = VEHICLE_DEFS.map(def => {
  const img = new Image();
  img.src = def.file;
  return img;
});

/* Starting positions spread across the left road */
const STARTS = [
  {x:60,  y:150, a:0},
  {x:60,  y:200, a:0},
  {x:60,  y:250, a:0},
  {x:60,  y:300, a:0},
  {x:60,  y:350, a:0},
  {x:60,  y:400, a:0},
  {x:100, y:150, a:0},
  {x:100, y:200, a:0},
  {x:100, y:250, a:0},
  {x:100, y:300, a:0},
  {x:100, y:350, a:0},
];

vehicles = VEHICLE_DEFS.map((def, i) => ({
  x: STARTS[i % STARTS.length].x,
  y: STARTS[i % STARTS.length].y,
  angle: STARTS[i % STARTS.length].a,
  speed: 0,
  def,
  image: carImages[i]
}));

document.addEventListener('keydown', e => { keys[e.key] = true; });
document.addEventListener('keyup',   e => { keys[e.key] = false; });

function getMousePos(canv, evt){
  const rect  = canv.getBoundingClientRect();
  const scaleX = canv.width  / rect.width;
  const scaleY = canv.height / rect.height;
  return { x:(evt.clientX-rect.left)*scaleX, y:(evt.clientY-rect.top)*scaleY };
}

/* Mouse / touch: select & drag */
canvas.addEventListener('mousedown', e => {
  if(placingTL) return;
  const m = getMousePos(canvas, e);
  let hit = null;
  for(let i = vehicles.length-1; i >= 0; i--){
    const c = vehicles[i];
    const hw = c.def.w/2 + 6, hh = c.def.h/2 + 6;
    if(m.x > c.x-hw && m.x < c.x+hw && m.y > c.y-hh && m.y < c.y+hh){
      hit = c; break;
    }
  }
  if(hit){
    selectedCar = hit; dragging = true;
    refreshVehiclePanel();
  } else {
    if(selectedCar){ selectedCar = null; refreshVehiclePanel(); }
  }
});
canvas.addEventListener('mousemove', e => {
  if(dragging && selectedCar){
    const m = getMousePos(canvas, e);
    selectedCar.x = m.x; selectedCar.y = m.y;
  }
});
canvas.addEventListener('mouseup', () => { dragging = false; });

function update(){
  if(!trafficEnabled || !selectedCar) return;
  const SPEED = 2.5;
  if(keys['ArrowUp'])    selectedCar.speed =  SPEED;
  else if(keys['ArrowDown'])  selectedCar.speed = -SPEED;
  else selectedCar.speed = 0;
  if(keys['ArrowLeft'])  selectedCar.angle -= 2.2;
  if(keys['ArrowRight']) selectedCar.angle += 2.2;
  const rad = selectedCar.angle * Math.PI/180;
  selectedCar.x += Math.sin(rad) * selectedCar.speed;
  selectedCar.y -= Math.cos(rad) * selectedCar.speed;
  // Clamp to canvas
  selectedCar.x = Math.max(10, Math.min(canvas.width-10,  selectedCar.x));
  selectedCar.y = Math.max(10, Math.min(canvas.height-10, selectedCar.y));
}

function drawCar(car){
  ctx.save();
  ctx.translate(car.x, car.y);
  ctx.rotate(car.angle * Math.PI/180);
  const hw = car.def.w/2, hh = car.def.h/2;
  if(car.image && car.image.complete && car.image.naturalWidth > 0){
    ctx.drawImage(car.image, -hw, -hh, car.def.w, car.def.h);
  } else {
    // Fallback coloured rectangle
    ctx.fillStyle = car.def.color;
    ctx.fillRect(-hw, -hh, car.def.w, car.def.h);
    ctx.fillStyle = '#000';
    ctx.font = '6px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(car.def.label.slice(0,5), 0, 2);
  }
  ctx.restore();

  // Selection ring
  if(car === selectedCar){
    ctx.save();
    ctx.translate(car.x, car.y);
    ctx.rotate(car.angle * Math.PI/180);
    const r = Math.max(car.def.w, car.def.h)/2 + 6;
    ctx.beginPath(); ctx.arc(0, 0, r, 0, Math.PI*2);
    ctx.strokeStyle = '#ff1744'; ctx.lineWidth = 2;
    ctx.setLineDash([5,4]); ctx.stroke(); ctx.setLineDash([]);
    ctx.restore();
  }

  // Special vehicle label badge
  if(car.def.special){
    ctx.save();
    ctx.font = 'bold 7px Arial';
    ctx.textAlign = 'center';
    const badge = car.def.special === 'police' ? '👮 POLICE' : '🚑 AMBULANCE';
    const col   = car.def.special === 'police' ? '#29b6f6' : '#ef5350';
    const tw = ctx.measureText(badge).width + 6;
    ctx.fillStyle = 'rgba(0,0,0,0.7)';
    ctx.fillRect(car.x - tw/2, car.y + car.def.h/2 + 2, tw, 10);
    ctx.fillStyle = col;
    ctx.fillText(badge, car.x, car.y + car.def.h/2 + 10);
    ctx.restore();
  }
}

function gameLoop(){
  update();
  updateTrafficLights();
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  if(map.complete && map.naturalWidth > 0){
    ctx.drawImage(map, 0, 0, canvas.width, canvas.height);
  } else {
    ctx.fillStyle = '#1a3a1a';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
  }
  drawTrafficLights();
  vehicles.forEach(car => drawCar(car));
  if(Math.random() < 0.04) refreshTLPanel();
  requestAnimationFrame(gameLoop);
}

map.onload = () => { gameLoopStarted = true; gameLoop(); };
let gameLoopStarted = false;
setTimeout(() => { if(!gameLoopStarted){ gameLoopStarted = true; gameLoop(); } }, 800);

/* Fullscreen */
function toggleFullscreen(){
  if(!document.fullscreenElement) canvas.requestFullscreen();
  else document.exitFullscreen();
}
document.addEventListener('fullscreenchange', () => {
  if(document.fullscreenElement === canvas){
    const scale = Math.min(screen.width/canvas.width, screen.height/canvas.height);
    canvas.style.width  = Math.round(canvas.width*scale)+'px';
    canvas.style.height = Math.round(canvas.height*scale)+'px';
    canvas.style.position='fixed'; canvas.style.top='50%'; canvas.style.left='50%';
    canvas.style.transform='translate(-50%,-50%)'; canvas.style.border='none'; canvas.style.zIndex=9999;
  } else {
    ['width','height','position','top','left','transform','border','zIndex'].forEach(p=>canvas.style[p]='');
    canvas.style.border='2px solid var(--border)';
  }
});

function toggleTraffic(){
  trafficEnabled = !trafficEnabled;
  document.getElementById('trafficBtn').textContent = '🚦 TRAFFIC: ' + (trafficEnabled ? 'ON' : 'OFF');
}

/* Vehicle panel — show thumbnails of all vehicles, highlight selected */
function refreshVehiclePanel(){
  const panel = document.getElementById('vehicle-panel');
  if(!panel) return;
  panel.innerHTML = vehicles.map((car, i) => `
    <div onclick="selectVehicle(${i})" title="${car.def.label}"
         style="cursor:pointer;padding:4px;border-radius:5px;border:1px solid ${car===selectedCar?'var(--gold)':'var(--border)'};
                background:${car===selectedCar?'rgba(245,197,24,0.1)':'var(--panel)'};transition:all .15s;
                display:flex;flex-direction:column;align-items:center;gap:3px;">
      <img src="${car.def.file}" style="width:18px;height:36px;object-fit:contain;"
           onerror="this.style.display='none';this.nextElementSibling.style.display='block'">
      <span style="display:none;width:18px;height:18px;background:${car.def.color};border-radius:2px;"></span>
      <span style="font-size:8px;color:${car===selectedCar?'var(--gold)':'#555'};text-align:center;line-height:1.2;max-width:44px;overflow:hidden;">${car.def.label}</span>
    </div>
  `).join('');
}

function selectVehicle(i){
  selectedCar = vehicles[i];
  refreshVehiclePanel();
}

/* Reset all vehicles to starting positions */
function resetVehicles(){
  vehicles.forEach((car, i) => {
    car.x = STARTS[i % STARTS.length].x;
    car.y = STARTS[i % STARTS.length].y;
    car.angle = 0; car.speed = 0;
  });
  selectedCar = null;
  refreshVehiclePanel();
}

/* ════════════════════════════════════════════════════════
   TRAFFIC LIGHT SYSTEM
════════════════════════════════════════════════════════ */

let trafficLights=[], selectedTL=null, draggingTL=false, placingTL=false, tlPaused=false, tlIdCounter=1;
const TL_CYCLE={red:300,green:240,yellow:60};
const TL_COL={red:'#ff1744',yellow:'#f5c518',green:'#00e676'};

function addTrafficLight(){ placingTL=true; canvas.style.cursor='crosshair'; }
function toggleAllTL(){
  tlPaused=!tlPaused;
  const btn=document.getElementById('tlPauseBtn');
  btn.textContent=tlPaused?'▶ RESUME LIGHTS':'⏸ PAUSE LIGHTS';
  btn.classList.toggle('active',tlPaused);
}
function deleteSelectedTL(){ if(!selectedTL)return; trafficLights=trafficLights.filter(t=>t!==selectedTL); selectedTL=null; refreshTLPanel(); }
function makeTL(x,y){ return{id:tlIdCounter++,x,y,state:'red',timer:TL_CYCLE.red,postH:22,houseW:14,houseH:38}; }

function updateTrafficLights(){
  if(tlPaused)return;
  trafficLights.forEach(tl=>{
    tl.timer--;
    if(tl.timer<=0){
      if(tl.state==='red'){tl.state='green';tl.timer=TL_CYCLE.green;}
      else if(tl.state==='green'){tl.state='yellow';tl.timer=TL_CYCLE.yellow;}
      else{tl.state='red';tl.timer=TL_CYCLE.red;}
    }
  });
}

function drawTrafficLight(tl){
  const x=tl.x,y=tl.y,hw=tl.houseW/2,hh=tl.houseH;
  ctx.fillStyle='#555'; ctx.fillRect(x-3,y,6,tl.postH);
  ctx.fillStyle='#111';
  ctx.strokeStyle=selectedTL===tl?'#00e5ff':'#333';
  ctx.lineWidth=selectedTL===tl?2:1;
  rrect(x-hw,y-hh,tl.houseW,hh,4); ctx.fill(); ctx.stroke();
  if(selectedTL===tl){
    ctx.beginPath(); ctx.arc(x,y-hh/2,hw+8,0,Math.PI*2);
    ctx.strokeStyle='rgba(0,229,255,0.4)'; ctx.lineWidth=2;
    ctx.setLineDash([4,3]); ctx.stroke(); ctx.setLineDash([]);
  }
  const bulbY=[y-hh+8,y-hh/2,y-10];
  ['red','yellow','green'].forEach((s,i)=>{
    const on=tl.state===s,bx=x,by=bulbY[i];
    if(on){ ctx.beginPath();ctx.arc(bx,by,7,0,Math.PI*2);ctx.fillStyle=TL_COL[s]+'44';ctx.fill(); }
    ctx.beginPath();ctx.arc(bx,by,4.5,0,Math.PI*2);
    ctx.fillStyle=on?TL_COL[s]:'#222';
    if(on){ctx.shadowColor=TL_COL[s];ctx.shadowBlur=10;}
    ctx.fill(); ctx.shadowBlur=0;
    ctx.beginPath();ctx.arc(bx,by,4.5,0,Math.PI*2);ctx.strokeStyle='#444';ctx.lineWidth=0.8;ctx.stroke();
  });
  if(tl.state==='green'){
    const g=ctx.createRadialGradient(x,y+4,0,x,y+30,30);
    g.addColorStop(0,'rgba(0,230,118,0.15)');g.addColorStop(1,'rgba(0,230,118,0)');
    ctx.fillStyle=g; ctx.beginPath();ctx.ellipse(x,y+20,20,12,0,0,Math.PI*2);ctx.fill();
  }
  const secs=Math.ceil(tl.timer/60);
  ctx.fillStyle='rgba(0,0,0,0.75)'; rrect(x-9,y-hh-14,18,12,3); ctx.fill();
  ctx.fillStyle=TL_COL[tl.state];ctx.font='bold 8px Arial';ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.fillText(secs+'s',x,y-hh-8);
}

function drawTrafficLights(){ trafficLights.forEach(tl=>drawTrafficLight(tl)); }

function rrect(x,y,w,h,r){
  ctx.beginPath();ctx.moveTo(x+r,y);ctx.lineTo(x+w-r,y);ctx.quadraticCurveTo(x+w,y,x+w,y+r);
  ctx.lineTo(x+w,y+h-r);ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h);ctx.lineTo(x+r,y+h);
  ctx.quadraticCurveTo(x,y+h,x,y+h-r);ctx.lineTo(x,y+r);ctx.quadraticCurveTo(x,y,x+r,y);ctx.closePath();
}

function tlHitTest(mx,my,tl){
  return mx>=tl.x-tl.houseW/2-6&&mx<=tl.x+tl.houseW/2+6&&my>=tl.y-tl.houseH-8&&my<=tl.y+tl.postH+4;
}

function cycleTLState(tl){
  if(tl.state==='red'){tl.state='green';tl.timer=TL_CYCLE.green;}
  else if(tl.state==='green'){tl.state='yellow';tl.timer=TL_CYCLE.yellow;}
  else{tl.state='red';tl.timer=TL_CYCLE.red;}
}

canvas.addEventListener('mousedown',e=>{
  const m=getMousePos(canvas,e);
  if(placingTL){
    placingTL=false; canvas.style.cursor='default';
    const tl=makeTL(m.x,m.y); trafficLights.push(tl); selectedTL=tl; refreshTLPanel(); return;
  }
  let hit=null;
  for(let i=trafficLights.length-1;i>=0;i--){
    if(tlHitTest(m.x,m.y,trafficLights[i])){ hit=trafficLights[i]; break; }
  }
  if(hit){ selectedTL=hit; draggingTL=true; hit._cx=m.x; hit._cy=m.y; refreshTLPanel(); e.stopImmediatePropagation(); return; }
  selectedTL=null; draggingTL=false; refreshTLPanel();
},true);

canvas.addEventListener('mousemove',e=>{
  if(!draggingTL||!selectedTL)return;
  const m=getMousePos(canvas,e); selectedTL.x=m.x; selectedTL.y=m.y; refreshTLPanel();
},true);

canvas.addEventListener('mouseup',e=>{
  if(draggingTL&&selectedTL){
    const m=getMousePos(canvas,e);
    if(Math.abs(m.x-(selectedTL._cx||m.x))<5&&Math.abs(m.y-(selectedTL._cy||m.y))<5) cycleTLState(selectedTL);
    draggingTL=false; refreshTLPanel();
  }
},true);

canvas.addEventListener('contextmenu',e=>{
  e.preventDefault();
  const m=getMousePos(canvas,e);
  for(let i=trafficLights.length-1;i>=0;i--){
    if(tlHitTest(m.x,m.y,trafficLights[i])){ trafficLights.splice(i,1); if(selectedTL===trafficLights[i])selectedTL=null; refreshTLPanel(); return; }
  }
});

function refreshTLPanel(){
  const list=document.getElementById('tl-status-list');
  if(!trafficLights.length){ list.innerHTML='<div style="color:#444;font-size:11px;padding:4px 0;">No lights yet</div>'; return; }
  list.innerHTML=trafficLights.map((tl,i)=>{
    const secs=Math.ceil(tl.timer/60);
    return`<div class="tl-status-row" onclick="focusTL(${i})">
      <div class="tl-dot ${tl.state}"></div>
      <span class="tl-status-name">Light #${tl.id}</span>
      <span class="tl-status-timer">${tl.state.toUpperCase()} ${secs}s</span>
    </div>`;
  }).join('');
}

function focusTL(i){ selectedTL=trafficLights[i]; cycleTLState(selectedTL); refreshTLPanel(); }

// Default traffic lights — positioned on the new map roundabout approaches
trafficLights.push(makeTL(480, 160)); trafficLights.push(makeTL(600, 270)); trafficLights.push(makeTL(480, 380));
trafficLights[0].state='green';  trafficLights[0].timer=TL_CYCLE.green;
trafficLights[1].state='yellow'; trafficLights[1].timer=TL_CYCLE.yellow;
trafficLights[2].state='red';    trafficLights[2].timer=TL_CYCLE.red;
refreshTLPanel();

// Init vehicle panel after DOM is ready
setTimeout(() => refreshVehiclePanel(), 100);
refreshTLPanel();

