function codeToFile(code){
  // e.g. "W.1" → "sign-W1.png", "P.32" → "sign-P32.png", "I.1" → "sign-I1.png"
  return 'sign-' + code.replace('.','') + '.png';
}

function buildSignsPage(){
  renderSignGroup('warning-signs',     SIGNS_DATA.warning);
  renderSignGroup('mandatory-signs',   SIGNS_DATA.mandatory);
  renderSignGroup('prohibitory-signs', SIGNS_DATA.prohibitory);
  renderSignGroup('priority-signs',    SIGNS_DATA.priority);
  renderSignGroup('info-signs',        SIGNS_DATA.info);
}

function renderSignGroup(containerId, signs){
  const el = document.getElementById(containerId);
  if(!el) return;
  el.innerHTML = signs.map((s)=>{
    const file = codeToFile(s.code);
    return `
    <div class="sign-card" onclick="this.classList.toggle('revealed')" title="${s.name}">
      <div class="sign-img-box">
        <img src="${file}" alt="${s.code}"
             onerror="this.classList.add('img-broken')">
        <span class="sign-fallback">${s.fallback||'🚧'}</span>
      </div>
      <div style="font-size:10px;color:#556;letter-spacing:1px;margin-bottom:3px;">${s.code}</div>
      <div class="sign-name">${s.name}</div>
      <div class="sign-desc">${s.desc}</div>
    </div>`;
  }).join('');
}

function scrollToCategory(sectionId, btn){
  // Update active button
  document.querySelectorAll('.signs-nav-btn').forEach(b=>b.classList.remove('active'));
  btn.classList.add('active');
  // Scroll the signs page to the section
  const section = document.getElementById(sectionId);
  const page    = document.getElementById('page-signs');
  if(section && page){
    // offsetTop relative to scrollable page
    const navH = document.getElementById('signs-nav').offsetHeight;
    const top  = section.offsetTop - navH - 8;
    page.scrollTo({top, behavior:'smooth'});
  }
}

// Highlight active nav button as user scrolls
document.getElementById('page-signs').addEventListener('scroll', function(){
  const sections = ['sec-warning','sec-mandatory','sec-prohibitory','sec-priority','sec-info'];
  const navBtns  = document.querySelectorAll('.signs-nav-btn');
  const scrollTop = this.scrollTop;
  let active = 0;
  sections.forEach((id,i)=>{
    const sec = document.getElementById(id);
    if(sec && sec.offsetTop - 120 <= scrollTop) active = i;
  });
  navBtns.forEach((b,i)=>b.classList.toggle('active', i===active));
});

