/* ════════════════════════════════════════════════════════
   TEXT-TO-SPEECH ENGINE (Web Speech API — works offline)
════════════════════════════════════════════════════════ */

/* ════════════════════════════════════════════════════════
   TEXT-TO-SPEECH ENGINE — TWO SEPARATE INSTANCES
   FAQ_TTS  → General Q&A page
   QUIZ_TTS → Quiz page
════════════════════════════════════════════════════════ */

function makeTTSInstance(barId, playBtnId, voiceSelId, rateId){
  return {
    synth:      window.speechSynthesis,
    voices:     [],
    rate:       0.95,
    autoRead:   false,
    currentBtn: null,
    supported:  !!window.speechSynthesis,
    _lastText:  '',
    _lastBtn:   null,
    _barId:     barId,
    _playId:    playBtnId,
    _voiceId:   voiceSelId,
    _rateId:    rateId,

    _bar()    { return document.getElementById(this._barId); },
    _playBtn(){ return document.getElementById(this._playId); },
    _voiceSel(){ return document.getElementById(this._voiceId); },

    loadVoices(){
      const sel = this._voiceSel();
      if(!sel) return;
      this.voices = this.synth.getVoices().filter(v =>
        v.lang.startsWith('en') || v.lang.startsWith('sw')
      );
      if(!this.voices.length) this.voices = this.synth.getVoices();
      sel.innerHTML = this.voices.map((v,i) =>
        `<option value="${i}">${v.name.replace(/Microsoft |Google /,'').slice(0,24)}</option>`
      ).join('');
      const pref = this.voices.findIndex(v => v.lang.startsWith('en'));
      if(pref >= 0) sel.value = pref;
    },

    _makeUtt(text){
      const utt = new SpeechSynthesisUtterance(text);
      utt.rate  = this.rate;
      const sel = this._voiceSel();
      const idx = sel ? parseInt(sel.value) : -1;
      if(idx >= 0 && this.voices[idx]) utt.voice = this.voices[idx];
      return utt;
    },

    _setSpeaking(on){
      const pb = this._playBtn(); const bar = this._bar();
      if(pb)  pb.textContent = on ? '⏸' : '▶';
      if(bar) bar.classList.toggle('tts-speaking', on);
    },

    speak(text, btnEl){
      if(!this.supported) return;
      this.synth.cancel();
      this._clearBtn();
      if(!text) return;
      const utt = this._makeUtt(text);
      if(btnEl){ this.currentBtn = btnEl; btnEl.classList.add('speaking'); }
      this._setSpeaking(true);
      utt.onend = utt.onerror = () => { this._clearBtn(); this._setSpeaking(false); };
      this._lastText = text; this._lastBtn = btnEl;
      this.synth.speak(utt);
    },

    speakThen(text, callback){
      if(!this.supported){ if(callback) callback(); return; }
      this.synth.cancel();
      this._clearBtn();
      if(!text){ if(callback) callback(); return; }
      const utt = this._makeUtt(text);
      this._setSpeaking(true);
      utt.onend = () => {
        this._clearBtn(); this._setSpeaking(false);
        if(callback) setTimeout(callback, 480);
      };
      utt.onerror = () => { this._clearBtn(); this._setSpeaking(false); };
      this._lastText = text;
      this.synth.speak(utt);
    },

    stop(){
      this.synth.cancel();
      this._clearBtn();
      this._setSpeaking(false);
    },

    playPause(){
      if(this.synth.speaking && !this.synth.paused){
        this.synth.pause(); const pb=this._playBtn(); if(pb) pb.textContent='▶';
      } else if(this.synth.paused){
        this.synth.resume(); const pb=this._playBtn(); if(pb) pb.textContent='⏸';
      } else if(this._lastText){
        this.speak(this._lastText, this._lastBtn);
      }
    },

    _clearBtn(){
      if(this.currentBtn) this.currentBtn.classList.remove('speaking');
      this.currentBtn = null;
    },

    praise(){
      const p=['Correct! Brilliant!','Correct! Well done!','That\'s right! Excellent!',
               'Correct! Great job!','Perfect! Keep it up!','Spot on! Brilliant work!','Correct! Fantastic!'];
      return p[Math.floor(Math.random()*p.length)];
    },

    quizText(q, answered){
      const L=['A','B','C','D'];
      let t=q.q+'. ';
      q.opts.forEach((o,i)=>{ t+=L[i]+'. '+o+'. '; });
      if(answered!==null&&answered!==undefined){
        t+='The correct answer is '+q.opts[q.ans]+'. ';
        if(q.explain) t+=q.explain;
      }
      return t;
    },

    faqText(item){
      let t=item.q+'. ';
      item.answers.forEach((a,i)=>{ if(item.answers.length>1) t+=(i+1)+'. '; t+=a+' '; });
      if(item.note) t+='Note: '+item.note;
      return t;
    }
  };
}

const FAQ_TTS  = makeTTSInstance('tts-bar-faq',  'faq-play-btn',  'faq-voice',  'faq-rate');
const QUIZ_TTS = makeTTSInstance('tts-bar-quiz', 'quiz-play-btn', 'quiz-voice', 'quiz-rate');

/* Sync voices to both instances on load */
if(window.speechSynthesis){
  window.speechSynthesis.onvoiceschanged = () => {
    FAQ_TTS.loadVoices();
    QUIZ_TTS.loadVoices();
  };
  FAQ_TTS.loadVoices();
  QUIZ_TTS.loadVoices();
}

/* ── FAQ bar handlers ── */
function faqTtsPlayPause()    { FAQ_TTS.playPause(); }
function faqTtsStop()          { FAQ_TTS.stop(); }
function faqTtsRateChange(v)   { FAQ_TTS.rate = parseFloat(v); }
function faqTtsToggleAuto(){
  FAQ_TTS.autoRead = !FAQ_TTS.autoRead;
  const btn = document.getElementById('faq-auto-btn');
  if(btn){
    btn.classList.toggle('active', FAQ_TTS.autoRead);
    btn.innerHTML = FAQ_TTS.autoRead ? '🔁 AUTO-READ: ON' : '🔁 AUTO-READ';
    btn.title     = FAQ_TTS.autoRead ? 'Auto-read ON — click to turn off' : 'Auto-read each question when opened';
  }
}

/* ── Quiz bar handlers ── */
function quizTtsPlayPause()   { QUIZ_TTS.playPause(); }
function quizTtsStop()         { QUIZ_TTS.stop(); }
function quizTtsRateChange(v)  { QUIZ_TTS.rate = parseFloat(v); }
function quizTtsToggleAuto(){
  QUIZ_TTS.autoRead = !QUIZ_TTS.autoRead;
  const btn = document.getElementById('quiz-auto-btn');
  if(btn){
    btn.classList.toggle('active', QUIZ_TTS.autoRead);
    btn.innerHTML = QUIZ_TTS.autoRead ? '🔁 AUTO-READ: ON' : '🔁 AUTO-READ';
    btn.title     = QUIZ_TTS.autoRead ? 'Auto-read ON — click to turn off' : 'Auto-read questions aloud';
  }
}

/* ── Speak functions called by cards ── */
function speakQuiz(btn){
  const q   = quizSet[quizIndex];
  const ans = quizAnswers[quizIndex];
  QUIZ_TTS.speak(QUIZ_TTS.quizText(q, ans), btn);
}

function speakFAQ(id, btn){
  const item = FAQ_DATA.find(f => f.id === id);
  if(!item) return;
  if(FAQ_TTS.currentBtn === btn && FAQ_TTS.synth.speaking){ FAQ_TTS.stop(); return; }
  FAQ_TTS.speak(FAQ_TTS.faqText(item), btn);
}

/* Legacy stubs so nothing else breaks */
const TTS = { stop(){ FAQ_TTS.stop(); QUIZ_TTS.stop(); }, autoRead: false };



