function buildFAQPage(){
  faqCurrentSet = [...FAQ_DATA];
  renderFAQ(FAQ_DATA);
}

function renderFAQ(data){
  faqCurrentSet = data;   // keep set in sync for auto-chain
  const list = document.getElementById('faq-list');
  list.innerHTML = data.map((item, i) => {
    // Build answer HTML — lettered list if multiple answers, plain if single
    const hasMany = item.answers.length > 1;
    const letters = ['A','B','C','D','E','F','G','H','I','J'];
    const answersHTML = hasMany
      ? item.answers.map((a, ai) =>
          `<div style="display:flex;gap:8px;margin-bottom:5px;padding-left:4px;border-left:2px solid rgba(245,197,24,0.35);">
            <span style="color:var(--gold);font-weight:bold;font-size:11px;min-width:16px;flex-shrink:0;">${letters[ai]}.</span>
            <span>${a}</span>
          </div>`
        ).join('')
      : `<div>${item.answers[0]}</div>`;

    const noteHTML = item.note
      ? `<div style="margin-top:8px;padding:6px 10px;background:rgba(41,182,246,0.07);border-left:2px solid var(--blue);font-size:11px;color:#7ab8d8;line-height:1.5;">📌 ${item.note}</div>`
      : '';

    return `
    <div class="faq-item" id="faq-${item.id}" data-tag="${item.tag}">
      <div class="faq-q" onclick="toggleFAQ(${item.id})">
        <span class="faq-q-num">Q${item.id}</span>
        <span class="faq-q-text">${item.q}</span>
        <button class="btn-speak" onclick="event.stopPropagation();toggleFAQ(${item.id});speakFAQ(${item.id},this)" title="Read aloud">🔊</button>
        <span class="faq-chevron">▼</span>
      </div>
      <div class="faq-a">
        <span class="faq-tag">${item.tag.toUpperCase().replace('-',' ')}</span>
        <div style="margin-top:4px;">${answersHTML}${noteHTML}</div>
      </div>
    </div>`;
  }).join('');
  // Update count display
  const countEl = document.getElementById('faq-search-count');
  if(countEl) countEl.textContent = data.length + ' questions';
}

function toggleFAQ(id){
  const el = document.getElementById('faq-' + id);
  if(!el) return;
  const wasOpen = el.classList.contains('open');

  if(FAQ_TTS.autoRead){
    if(wasOpen){
      // Tapping an open item while auto-read is on → stop and collapse
      FAQ_TTS.stop();
      el.classList.remove('open');
    } else {
      // Start auto-chain from this question
      const item = faqCurrentSet.find(f => f.id === id) || FAQ_DATA.find(f => f.id === id);
      if(item) faqOpenAndSpeak(item);
    }
  } else {
    el.classList.toggle('open');
    if(!el.classList.contains('open')) FAQ_TTS.stop();
  }
}

/* Open an item, scroll it into view, speak it, then auto-chain to next */
function faqOpenAndSpeak(item){
  FAQ_TTS.stop();
  // Close all other open items
  document.querySelectorAll('.faq-item.open').forEach(el => el.classList.remove('open'));

  const el = document.getElementById('faq-' + item.id);
  if(!el) return;
  el.classList.add('open');
  el.scrollIntoView({behavior:'smooth', block:'nearest'});

  if(!FAQ_TTS.autoRead) return;

  const speakBtn = el.querySelector('.btn-speak');
  const idx      = faqCurrentSet.findIndex(f => f.id === item.id);
  const nextItem = faqCurrentSet[idx + 1] || null;

  FAQ_TTS.speakThen(FAQ_TTS.faqText(item), nextItem
    ? () => { faqOpenAndSpeak(nextItem); }   // chain to next
    : () => { /* last item — stay open */ }
  );
  if(speakBtn) speakBtn.classList.add('speaking');
}

let activeFilter = 'all';
let activeSearch = '';
let faqCurrentSet = [];   // populated by renderFAQ; used by auto-chain


function filterFAQ(tag){
  FAQ_TTS.stop();
  activeFilter = tag;
  activeSearch = '';
  const searchBox = document.getElementById('faq-search');
  if(searchBox) searchBox.value = '';
  document.querySelectorAll('#faq-filters .quiz-btn').forEach(b => b.classList.remove('primary'));
  document.getElementById('ff-' + tag)?.classList.add('primary');
  const filtered = tag === 'all' ? FAQ_DATA : FAQ_DATA.filter(q => q.tag === tag);
  renderFAQ(filtered);
}

function searchFAQ(val){
  FAQ_TTS.stop();
  activeSearch = val.trim().toLowerCase();
  if(!activeSearch){ filterFAQ(activeFilter); return; }
  // Check if numeric — jump to that Q number
  const num = parseInt(val);
  if(!isNaN(num) && num >= 1 && num <= FAQ_DATA.length){
    // Show only that question, scroll to it
    renderFAQ(FAQ_DATA);
    document.querySelectorAll('.faq-item').forEach(el => {
      el.style.display = el.id === 'faq-' + num ? 'block' : 'none';
    });
    const target = document.getElementById('faq-' + num);
    if(target){ target.classList.add('open'); target.scrollIntoView({behavior:'smooth',block:'center'}); }
    const countEl = document.getElementById('faq-search-count');
    if(countEl) countEl.textContent = '1 match';
    return;
  }
  // Keyword search
  const matched = FAQ_DATA.filter(q =>
    q.q.toLowerCase().includes(activeSearch) ||
    q.answers.some(a => a.toLowerCase().includes(activeSearch)) ||
    (q.note && q.note.toLowerCase().includes(activeSearch)) ||
    q.tag.toLowerCase().includes(activeSearch)
  );
  renderFAQ(matched);
  // Auto-open if only one result
  if(matched.length === 1){
    const el = document.getElementById('faq-' + matched[0].id);
    if(el) el.classList.add('open');
  }
}

