let quizInitDone=false, quizIndex=0, quizScore=0, quizAnswers=[], quizSet=[];
let activeQuizTag='all';

const TAG_LABELS={
  all:'ALL TOPICS',
  rules:'RULES', overtaking:'OVERTAKING', signs:'ALL SIGNS',
  'signs-warning':'⚠ WARNING SIGNS', 'signs-mandatory':'🔵 MANDATORY SIGNS',
  'signs-prohibitory':'🔴 PROHIBITORY SIGNS', 'signs-priority':'🛑 PRIORITY SIGNS',
  'signs-info':'ℹ INFORMATORY SIGNS',
  lights:'LIGHTS', parking:'PARKING', safety:'SAFETY',
  vehicle:'VEHICLE', 'model-town':'MODEL TOWN'
};

function initQuiz(tag){
  quizInitDone=true;
  activeQuizTag=tag||activeQuizTag||'all';
  if(activeQuizTag==='all'){
    quizSet=[...QUIZ_QUESTIONS];
  } else if(activeQuizTag.startsWith('signs-')){
    const sub=activeQuizTag.replace('signs-','');
    quizSet=QUIZ_QUESTIONS.filter(q=>q.tag==='signs' && (q.ref||'').toLowerCase().startsWith(sub.charAt(0).toUpperCase()));
    // Fallback: filter by subtag field
    if(!quizSet.length) quizSet=QUIZ_QUESTIONS.filter(q=>q.subtag===activeQuizTag||q.tag===activeQuizTag);
  } else {
    quizSet=QUIZ_QUESTIONS.filter(q=>q.tag===activeQuizTag);
  }
  if(!quizSet.length) quizSet=QUIZ_QUESTIONS.filter(q=>q.tag==='signs');
  // Shuffle
  for(let i=quizSet.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[quizSet[i],quizSet[j]]=[quizSet[j],quizSet[i]];}
  quizIndex=0; quizScore=0;
  quizAnswers=new Array(quizSet.length).fill(null);
  renderQuizQuestion();
}

function renderQuizStart(){
  const wrap=document.getElementById('quiz-wrap');
  const mainTags=['all','rules','overtaking','signs','lights','parking','safety','vehicle','model-town'];
  const signTags=['signs-warning','signs-mandatory','signs-prohibitory','signs-priority','signs-info'];

  function countTag(t){
    if(t==='all') return QUIZ_QUESTIONS.length;
    if(t==='signs') return QUIZ_QUESTIONS.filter(q=>q.tag==='signs').length;
    if(t.startsWith('signs-')){
      const letter=t.replace('signs-','').charAt(0).toUpperCase();
      return QUIZ_QUESTIONS.filter(q=>q.tag==='signs'&&(q.ref||'').startsWith(letter)).length||
             QUIZ_QUESTIONS.filter(q=>q.subtag===t).length;
    }
    return QUIZ_QUESTIONS.filter(q=>q.tag===t).length;
  }

  const tagCol={rules:'#29b6f6',overtaking:'#ff9800',signs:'#ab47bc',lights:'#f5c518',parking:'#26a69a',safety:'#ef5350',vehicle:'#66bb6a','model-town':'#8d6e63','signs-warning':'#e65100','signs-mandatory':'#0050a8','signs-prohibitory':'#cc0000','signs-priority':'#b71c1c','signs-info':'#01579b'};

  function cardBtn(t){
    const n=countTag(t); const col=tagCol[t]||'#555';
    const active=t===activeQuizTag;
    return`<button onclick="initQuiz('${t}')" style="
        padding:14px 16px;background:var(--panel);border:1px solid ${active?'var(--gold)':'var(--border)'};
        color:${active?'var(--gold)':'var(--dim)'};
        font-size:12px;font-weight:bold;letter-spacing:1px;cursor:pointer;border-radius:6px;
        text-align:left;transition:all .18s;position:relative;overflow:hidden;"
      onmouseover="this.style.borderColor='var(--gold)';this.style.color='var(--gold)'"
      onmouseout="this.style.borderColor='${active?'var(--gold)':'var(--border)'}';this.style.color='${active?'var(--gold)':'var(--dim)'}'">
      <div style="position:absolute;top:0;left:0;width:3px;height:100%;background:${col};"></div>
      <div style="padding-left:8px;">${TAG_LABELS[t]}</div>
      <div style="font-size:20px;color:${col};margin-top:4px;padding-left:8px;">${n}</div>
      <div style="font-size:10px;color:#444;padding-left:8px;">question${n!==1?'s':''}</div>
    </button>`;
  }

  wrap.innerHTML=`
    <div style="margin-bottom:20px;">
      <div style="font-size:18px;font-weight:bold;color:var(--gold);letter-spacing:2px;margin-bottom:4px;">SELECT TOPIC</div>
      <div style="font-size:12px;color:var(--dim);">Choose a topic or sub-category. Questions shuffle each session.</div>
    </div>

    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(170px,1fr));gap:10px;margin-bottom:20px;">
      ${mainTags.map(cardBtn).join('')}
    </div>

    <div style="font-size:11px;font-weight:bold;color:var(--gold);letter-spacing:2px;margin:16px 0 10px;border-left:3px solid var(--gold);padding-left:10px;">SIGNS BY CATEGORY</div>
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(170px,1fr));gap:10px;margin-bottom:28px;">
      ${signTags.map(cardBtn).join('')}
    </div>`;
}

/* Return sign image HTML if this question has a specific sign ref (e.g. W.1, P.32) */
function quizSignImage(q){
  if(q.tag !== 'signs') return '';
  const ref = (q.ref || '');
  // Only show for single-sign refs like W.1, P.32, M.3, R.1, A.1, I.28 — not "W series", "Q25" etc.
  if(!/^[WMPRAISs]\.\d/.test(ref) && !/^R\.\d/.test(ref) && !/^A\.\d/.test(ref)) return '';
  const file = 'sign-' + ref.replace('.','') + '.png';
  return `<div style="display:flex;justify-content:center;margin-bottom:14px;">
    <div style="background:#1a2230;border:1px solid var(--border);border-radius:8px;padding:10px;display:inline-flex;flex-direction:column;align-items:center;gap:6px;">
      <img src="${file}" alt="${ref}"
           style="max-width:90px;max-height:90px;object-fit:contain;display:block;"
           onerror="this.parentElement.style.display='none'">
      <span style="font-size:10px;color:#556;letter-spacing:1px;">${ref}</span>
    </div>
  </div>`;
}

function renderQuizQuestion(){
  const wrap=document.getElementById('quiz-wrap');
  if(!quizSet.length){ renderQuizStart(); return; }
  if(quizIndex>=quizSet.length){ renderQuizResult(wrap); return; }

  const q=quizSet[quizIndex];
  const pct=Math.round((quizIndex/quizSet.length)*100);
  const answered=quizAnswers[quizIndex];
  const letters=['A','B','C','D'];
  const tagCol={rules:'#29b6f6',overtaking:'#ff9800',signs:'#ab47bc',lights:'#f5c518',parking:'#26a69a',safety:'#ef5350',vehicle:'#66bb6a','model-town':'#8d6e63'};

  wrap.innerHTML=`
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;flex-wrap:wrap;gap:6px;">
      <div style="display:flex;align-items:center;gap:8px;">
        <span style="font-size:12px;color:var(--dim);letter-spacing:1px;">Q ${quizIndex+1} / ${quizSet.length}</span>
        <span style="background:${tagCol[q.tag]||'#555'};color:black;font-size:10px;font-weight:bold;padding:2px 8px;border-radius:10px;letter-spacing:1px;">${(q.tag||'').toUpperCase().replace('-',' ')}</span>
        ${q.ref?`<span style="font-size:10px;color:#444;letter-spacing:1px;">ref ${q.ref}</span>`:''}
      </div>
      <span class="quiz-score-badge">SCORE: ${quizScore}/${quizIndex}</span>
    </div>
    <div class="quiz-progress-bar-wrap"><div class="quiz-progress-bar" style="width:${pct}%"></div></div>

    <div class="quiz-card">
      ${quizSignImage(q)}
      <div style="display:flex;align-items:flex-start;gap:10px;margin-bottom:14px;">
        <div class="quiz-question" style="flex:1;margin-bottom:0;">${q.q}</div>
        <button class="btn-speak" id="quiz-speak-btn" onclick="speakQuiz(this)" title="Read question aloud" style="flex-shrink:0;margin-top:2px;">🔊</button>
      </div>
      <div class="quiz-options">
        ${q.opts.map((opt,i)=>{
          let cls='quiz-option';
          if(answered!==null){
            cls+=' locked';
            if(i===q.ans) cls+=' correct';
            else if(i===answered&&answered!==q.ans) cls+=' wrong';
          }
          return `<div class="${cls}" onclick="answerQuiz(${i})">
            <div class="quiz-option-letter">${letters[i]}</div>
            <span>${opt}</span>
          </div>`;
        }).join('')}
      </div>
      ${answered!==null?`
      <div class="quiz-feedback show ${answered===q.ans?'correct-fb':'wrong-fb'}">
        ${answered===q.ans?'✓ Correct! ':`✗ Incorrect. Correct answer: <strong>${q.opts[q.ans]}</strong>. `}${q.explain}
        <div style="margin-top:8px;">
          <button class="btn-speak" id="quiz-explain-btn" onclick="speakQuiz(this)" title="Read explanation">🔊 Read explanation</button>
        </div>
      </div>`:''}
    </div>

    <div class="quiz-nav">
      <button class="quiz-btn" onclick="renderQuizStart()" style="border-color:#444;color:#666;">⊙ TOPICS</button>
      ${quizIndex>0?`<button class="quiz-btn" onclick="quizGo(${quizIndex-1})">◀ PREV</button>`:''}
      ${answered!==null
        ?`<button class="quiz-btn primary" onclick="quizGo(${quizIndex+1})">${quizIndex<quizSet.length-1?'NEXT ▶':'FINISH ▶'}</button>`
        :`<button class="quiz-btn" style="opacity:.4;cursor:default">Answer to continue</button>`}
    </div>
  `;

  // Auto-read: speak question when card loads
  if(QUIZ_TTS.autoRead && answered===null){
    setTimeout(()=>{
      const btn=document.getElementById('quiz-speak-btn');
      if(btn) speakQuiz(btn);
    }, 300);
  }
}

function answerQuiz(optIdx){
  if(quizAnswers[quizIndex]!==null) return;
  quizAnswers[quizIndex] = optIdx;
  const q       = quizSet[quizIndex];
  const correct = optIdx === q.ans;
  if(correct) quizScore++;
  renderQuizQuestion();

  if(QUIZ_TTS.autoRead){
    if(correct){
      QUIZ_TTS.speakThen(QUIZ_TTS.praise(), () => {
        quizGo(quizIndex + 1);
      });
    } else {
      const wrongText = `Wrong. The correct answer is: ${q.opts[q.ans]}. ${q.explain}`;
      QUIZ_TTS.speakThen(wrongText, () => {
        quizGo(quizIndex + 1);
      });
    }
  }
}

function quizGo(idx){
  QUIZ_TTS.stop();
  quizIndex=Math.max(0,Math.min(quizSet.length,idx));
  renderQuizQuestion();
}

function renderQuizResult(wrap){
  const total=quizSet.length;
  const pct=Math.round((quizScore/total)*100);
  const grade=pct>=80?'DISTINCTION':pct>=70?'MERIT':pct>=50?'PASS':'FAIL';
  const gradeCol=pct>=70?'var(--green)':pct>=50?'var(--gold)':'var(--red)';
  const msg=pct>=80?'Excellent! You are ready for the NTSA theory test.':
            pct>=70?'Good result. Review the questions you missed.':
            pct>=50?'Borderline pass. More revision is recommended.':
            'You need more study. Review the Q&A section and retry.';
  wrap.innerHTML=`
    <div class="quiz-result">
      <div style="font-size:13px;color:var(--dim);letter-spacing:2px;margin-bottom:12px;">${TAG_LABELS[activeQuizTag]||'ALL TOPICS'}</div>
      <div class="quiz-result-score" style="color:${gradeCol}">${pct}%</div>
      <div class="quiz-result-label">${quizScore} / ${total} CORRECT</div>
      <div class="quiz-result-grade" style="color:${gradeCol}">${grade}</div>
      <div class="quiz-result-bar-wrap">
        <div class="quiz-result-bar" style="width:${pct}%;background:${gradeCol}"></div>
      </div>
      <p style="font-size:13px;color:var(--dim);margin-bottom:28px;">${msg}</p>
      <div style="display:flex;gap:10px;justify-content:center;flex-wrap:wrap;">
        <button class="quiz-btn primary" onclick="initQuiz()">↺ RETRY</button>
        <button class="quiz-btn" onclick="quizReview()">📋 REVIEW</button>
        <button class="quiz-btn" onclick="renderQuizStart()">⊙ CHANGE TOPIC</button>
        <button class="quiz-btn" onclick="showPage('general',2)">📖 STUDY Q&amp;A</button>
      </div>
    </div>`;
}

function quizReview(){
  const wrap=document.getElementById('quiz-wrap');
  const letters=['A','B','C','D'];
  const rows=quizSet.map((q,i)=>{
    const ans=quizAnswers[i];
    const correct=ans===q.ans;
    return`<div style="background:var(--panel);border:1px solid ${correct?'var(--green)':'var(--red)'};border-radius:6px;padding:14px 16px;margin-bottom:10px;">
      <div style="font-size:11px;color:var(--dim);margin-bottom:6px;">Q${i+1} ${q.ref?'· '+q.ref:''} · ${correct?'<span style=color:var(--green)>✓ CORRECT</span>':'<span style=color:var(--red)>✗ WRONG</span>'}</div>
      <div style="font-size:13px;font-weight:bold;margin-bottom:10px;">${q.q}</div>
      <div style="font-size:12px;color:var(--dim);">Your answer: <span style="color:${correct?'var(--green)':'var(--red)'};">${ans!==null?letters[ans]+'. '+q.opts[ans]:'Not answered'}</span></div>
      ${!correct?`<div style="font-size:12px;color:var(--green);margin-top:4px;">Correct: ${letters[q.ans]}. ${q.opts[q.ans]}</div>`:''}
      <div style="font-size:11px;color:#555;margin-top:8px;line-height:1.6;">${q.explain}</div>
    </div>`;
  }).join('');
  wrap.innerHTML=`
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:20px;flex-wrap:wrap;gap:8px;">
      <div style="font-size:16px;font-weight:bold;color:var(--gold);">ANSWER REVIEW</div>
      <div style="display:flex;gap:8px;flex-wrap:wrap;">
        <button class="quiz-btn primary" onclick="initQuiz()">↺ RETRY</button>
        <button class="quiz-btn" onclick="renderQuizStart()">⊙ TOPICS</button>
      </div>
    </div>${rows}`;
}

